-        } catch (ClassNotFoundException e) {
-            throw new IllegalStateException(e);
-        }
-        try (var libStream = OnnxRuntime.class.getResourceAsStream(libResource)) {
-            var libFile = File.createTempFile("libonnxruntime", "");
